def entity_catalog() -> dict:
    definitions = [EntityTypeDefinition(**item).to_dict() for item in ENTITY_DEFINITIONS]
    grouped: dict[str, list[dict]] = {family: [] for family in FAMILY_ORDER}
    for item in definitions:
        grouped.setdefault(item["family"], []).append(item)
    return {"families": FAMILY_ORDER, "family_descriptions": FAMILY_DESCRIPTIONS, "types": definitions, "groups": grouped, "status_values": ["verified", "strong", "probable", "weak", "candidate", "noise", "contradicted", "insufficient_evidence"]}

def get_entity_type(entity_type: str) -> dict | None:
    clean = (entity_type or "").strip().lower()
    return next((item for item in ENTITY_DEFINITIONS if item["id"].lower() == clean), None)
